compliant.code:
package main

import (
    "fmt"
)

// Compliant: Proper Go syntax that parses correctly

// GOOD: Proper function syntax
func goodFunction() {
    if true {
        fmt.Println("hello")
    } // Properly closed brace
}

// GOOD: Valid function with parameters
func anotherGoodFunction(param string) {
    fmt.Println(param)
}

// GOOD: Proper parentheses
func calculateSum() int {
    return (1 + 2 + 3)
}

// GOOD: Valid variable declarations
var validVar string = "valid"
var anotherVar = "also valid"
validShort := "short declaration"

// GOOD: Proper import statements
import (
    "encoding/json"
    "net/http"
)

// GOOD: Valid struct syntax
type User struct {
    Name string
    Age  int
    Email string
}

// GOOD: Valid interface syntax
type Writer interface {
    Write(data []byte) (int, error)
    Close() error
}

// GOOD: Valid method with proper receiver
func (u *User) GetName() string {
    return u.Name
}

func (u *User) SetName(name string) {
    u.Name = name
}

// GOOD: Valid goroutine syntax
func startWorker() {
    go func() {
        fmt.Println("worker")
    }()
}

// GOOD: Valid channel operations
func channelExample() {
    ch := make(chan string, 1)
    ch <- "message"
    msg := <-ch
    fmt.Println(msg)
}

// GOOD: Valid defer statement
func deferExample() {
    defer fmt.Println("deferred")
    fmt.Println("immediate")
}

// GOOD: Valid switch statement
func switchExample(value int) {
    switch value {
    case 1:
        fmt.Println("one")
    case 2:
        fmt.Println("two")
    default:
        fmt.Println("other")
    }
}

// GOOD: Valid range loop
func rangeExample() {
    slice := []string{"a", "b", "c"}
    for i, v := range slice {
        fmt.Printf("Index: %d, Value: %s\n", i, v)
    }
}

// GOOD: Valid map operations
func mapExample() {
    m := make(map[string]int)
    m["key"] = 42
    value, exists := m["key"]
    if exists {
        fmt.Println(value)
    }
}

// GOOD: Valid error handling
func errorExample() error {
    if err := someOperation(); err != nil {
        return fmt.Errorf("operation failed: %w", err)
    }
    return nil
}

func someOperation() error {
    return nil
}
